mapper.select:
SELECT et.id AS typeId, etm.evaluator_no AS evaluatorNo, eval_emp.name AS evaluatorName, etm.evaluatee_no AS evaluateeNo, e.name AS evaluateeName, et.name AS evalName, etm.step, e.dept_id AS deptId, d.name AS deptName, e.position AS position, e.emp_no AS empNo, et.start_date AS startDate, et.end_date AS endDate, cc.name AS statusName FROM eval_target_mapping_52 etm JOIN eval_type_52 et ON et.id = etm.eval_type_id JOIN employee_52 e ON e.emp_no = etm.evaluatee_no LEFT JOIN department_52 d ON d.id = e.dept_id LEFT JOIN employee_52 eval_emp ON eval_emp.emp_no = etm.evaluator_no LEFT JOIN code_common_52 cc ON cc.code = CAST(etm.status AS VARCHAR) LEFT JOIN code_group_52 cg ON cg.id = cc.group_id AND cg.group_code = 'EVAL_STATUS'
et.name LIKE '%다면평가%'
AND etm.evaluator_no = #{userNo}
AND etm.evaluatee_no = #{userNo}

SELECT q.id AS questionId, q.category AS categoryName, q.explanation AS goalDesc, ea.score AS selfScore, ea.content AS selfFeedback FROM eval_question_52 q
LEFT JOIN eval_answer_52 ea ON ea.question_id = q.id
LEFT JOIN eval_target_mapping_52 etm ON etm.id = ea.mapping_id AND etm.evaluatee_no = #{empNo}
WHERE q.type_id = #{typeId}
